create table dirkspzm32.pzm_personal_hist (
    pers_nr                 number(*, 0) not null enable,
    pers_land               varchar2(255 char),
    pers_region_code        varchar2(255 char),
    pers_pb_id              number(*, 0),
    pers_abt_id             number(*, 0),
    pers_kst_id             number(*, 0),
    pers_eintrittsdatum     date,
    pers_austrittdatum      date,
    pers_sm_name            varchar2(100 char),
    pers_befristet_bis      date,
    pers_urlaub_anspr_wert  number(*, 3),
    pers_urlaub_anspr_aa_id number(*, 0),
    pers_startdatum         date,
    tarif_name              varchar2(50 char),
    old_land                varchar2(255 char),
    old_region_code         varchar2(255 char),
    old_pb_id               number(*, 0),
    old_abt_id              number(*, 0),
    old_kst_id              number(*, 0),
    old_eintrittsdatum      date,
    old_austrittdatum       date,
    old_sm_name             varchar2(100 char),
    old_befristet_bis       date,
    old_urlaub_anspr_wert   number(*, 3),
    old_urlaub_anspr_aa_id  number(*, 0),
    old_startdatum          date,
    old_tarif_name          varchar2(50 char),
    created_date            date default sysdate not null enable,
    created_login_id        number(*, 0) default - 1
);

alter table dirkspzm32.pzm_personal_hist
    add constraint pk_personal_hist_pers_nr primary key ( pers_nr,
                                                          created_date )
        using index enable;


